import React, { useMemo } from "react"
import { ConfigProvider, theme as antTheme, App as AntdApp } from "antd"
import { useTheme } from "./theme-provider"
import { useTranslation } from "./i18n-provider"

export function AntdProvider({ children }: { children: React.ReactNode }) {
  const { theme } = useTheme()
  const { locale } = useTranslation()

  const isDark = theme === "dark"

  // colorPrimary, colorBgBase, colorTextBase MUST be real hex values —
  // Ant Design's algorithm derives placeholder/disabled/hover colors from them
  // and cannot resolve CSS variable strings.
  /* eslint-disable react-hooks/exhaustive-deps */
  const seed = useMemo(() => {
    const get = (v: string) => getComputedStyle(document.documentElement).getPropertyValue(v).trim()
    return {
      colorPrimary: get("--primary-500"),
      colorBgBase: isDark ? "#161B22" : "#FFFFFF",
      colorTextBase: isDark ? "#E6E8EB" : "#131313"
    }
  }, [theme])
  /* eslint-enable react-hooks/exhaustive-deps */

  return (
    <ConfigProvider
      direction={locale === "ar" ? "rtl" : "ltr"}
      theme={{
        algorithm: isDark ? antTheme.darkAlgorithm : antTheme.defaultAlgorithm,
        token: {
          colorPrimary: seed.colorPrimary,
          colorBgBase: seed.colorBgBase,
          colorTextBase: seed.colorTextBase,
          fontFamily:
            "'Inter', system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif",
          fontSize: 13,
          borderRadius: 6,
          colorBgContainer: "var(--color-bg-container)",
          colorBgElevated: "var(--color-bg-elevated)",
          colorBgLayout: "var(--color-bg-layout)",
          colorBorder: "var(--color-border)",
          colorBorderSecondary: "var(--color-border-secondary)",
          colorTextSecondary: isDark ? "#9BA3AF" : "#64748B",
          colorTextTertiary: isDark ? "#6B7280" : "#94A3B8",
          colorFill: isDark ? "rgba(255,255,255,0.06)" : "rgba(0,0,0,0.04)",
          colorFillSecondary: isDark ? "rgba(255,255,255,0.04)" : "rgba(0,0,0,0.02)"
        },
        components: {
          Menu: {
            itemBg: "transparent",
            subMenuItemBg: "transparent",
            itemColor: isDark ? "#9BA3AF" : "#475569",
            itemHoverColor: isDark ? "#E6E8EB" : "#0F172A",
            itemHoverBg: isDark ? "rgba(255,255,255,0.06)" : "rgba(8,141,238,0.06)",
            itemSelectedColor: seed.colorPrimary,
            itemSelectedBg: isDark ? "rgba(63,168,244,0.18)" : "rgba(8,141,238,0.1)",
            itemActiveBg: isDark ? "rgba(63,168,244,0.18)" : "rgba(8,141,238,0.1)",
            groupTitleColor: isDark ? "#6B7280" : "#94A3B8",
            itemBorderRadius: 0,
            itemMarginInline: 0,
            itemMarginBlock: 1,
            iconSize: 15
          },
          Layout: {
            headerBg: "var(--color-bg-container)",
            bodyBg: "var(--color-bg-layout)",
            siderBg: "var(--color-bg-container)"
          },
          Button: {
            borderRadius: 6
          },
          Input: {
            borderRadius: 6
          },
          Select: {
            borderRadius: 6
          },
          Modal: {
            borderRadiusLG: 10
          },
          Card: {
            borderRadiusLG: 8
          }
        }
      }}>
      <AntdApp>{children}</AntdApp>
    </ConfigProvider>
  )
}
