import {
  UserOutlined,
  SunOutlined,
  MoonOutlined,
  BellOutlined,
  MenuFoldOutlined,
  MenuUnfoldOutlined,
  GlobalOutlined,
  LogoutOutlined,
  CaretDownOutlined
} from "@ant-design/icons"
import {
  Layout,
  Button,
  theme,
  Avatar,
  Dropdown,
  Space,
  Typography,
  Badge,
  Popover,
  Divider
} from "antd"
import { useNavigate, useLocation } from "react-router-dom"
import { useTheme } from "../../lib/providers/theme-provider"
import { useTranslation } from "../../lib/providers/i18n-provider"

const { Header } = Layout

interface DashboardHeaderProps {
  collapsed: boolean
  onToggleCollapse: () => void
}

const pathMeta: Record<string, { breadcrumb: string[]; title: string }> = {
  "/users": { breadcrumb: ["User Management", "Users"], title: "Users" },
  "/dashboard": { breadcrumb: ["Dashboard"], title: "Dashboard" },
  "/roles": { breadcrumb: ["User Management", "Roles & Permissions"], title: "Roles & Permissions" }
}

export default function DashboardHeader({ collapsed, onToggleCollapse }: DashboardHeaderProps) {
  const {
    token: { colorBgContainer, colorBorder, colorPrimary, colorTextSecondary }
  } = theme.useToken()
  const navigate = useNavigate()
  const location = useLocation()
  const { theme: currentTheme, toggleTheme } = useTheme()
  const { locale, setLocale, t } = useTranslation()

  const meta = pathMeta[location.pathname] ?? { breadcrumb: ["Home"], title: "Dashboard" }

  const handleMenuClick = ({ key }: { key: string }) => {
    if (key === "logout") navigate("/login")
  }

  const menuItems = [
    { key: "profile", label: t("profile"), icon: <UserOutlined /> },
    { type: "divider" as const },
    { key: "logout", label: t("logout"), icon: <LogoutOutlined />, danger: true }
  ]

  const notifications = [
    {
      id: 1,
      title: t("newUserRegistered"),
      description: t("newUserSignedUp"),
      time: "5 min ago",
      read: false
    },
    {
      id: 2,
      title: t("systemUpdate"),
      description: t("systemMaintenance"),
      time: "1 hour ago",
      read: false
    },
    { id: 3, title: t("taskAssigned"), description: t("newTask"), time: "2 hours ago", read: true }
  ]

  const unreadCount = notifications.filter((n) => !n.read).length

  const notificationContent = (
    <div style={{ width: 310 }}>
      <div
        style={{
          display: "flex",
          justifyContent: "space-between",
          alignItems: "center",
          paddingBottom: 10,
          marginBottom: 4,
          borderBottom: `1px solid ${colorBorder}`
        }}>
        <Typography.Text strong style={{ fontSize: 13 }}>
          {t("notifications")}
        </Typography.Text>
        <Badge count={unreadCount} size="small" />
      </div>
      <div style={{ maxHeight: 280, overflowY: "auto" }}>
        {notifications.map((item) => (
          <div
            key={item.id}
            style={{
              padding: "10px 0",
              borderBottom: `1px solid ${colorBorder}`,
              opacity: item.read ? 0.5 : 1,
              cursor: "pointer"
            }}>
            <div style={{ display: "flex", gap: 10, alignItems: "flex-start" }}>
              <Avatar
                style={{ backgroundColor: item.read ? colorBorder : colorPrimary, flexShrink: 0 }}
                icon={<BellOutlined />}
                size={28}
              />
              <div>
                <Typography.Text style={{ fontSize: 13, fontWeight: 500, display: "block" }}>
                  {item.title}
                </Typography.Text>
                <Typography.Text type="secondary" style={{ fontSize: 11 }}>
                  {item.description}
                </Typography.Text>
                <Typography.Text
                  type="secondary"
                  style={{ fontSize: 10, display: "block", marginTop: 2 }}>
                  {item.time}
                </Typography.Text>
              </div>
            </div>
          </div>
        ))}
      </div>
      <div style={{ paddingTop: 8, textAlign: "center" }}>
        <Typography.Link style={{ fontSize: 12 }}>{t("viewAllNotifications")}</Typography.Link>
      </div>
    </div>
  )

  return (
    <Header
      style={{
        padding: 0,
        background: colorBgContainer,
        display: "flex",
        alignItems: "center",
        justifyContent: "space-between",
        paddingInlineEnd: 20,
        borderBottom: `1px solid ${colorBorder}`,
        boxShadow: "0 1px 4px rgba(0,0,0,0.06)",
        height: 56,
        flexShrink: 0,
        position: "sticky",
        top: 0,
        zIndex: 100
      }}>
      {/* Left */}
      <div style={{ display: "flex", alignItems: "center" }}>
        <Button
          type="text"
          icon={collapsed ? <MenuUnfoldOutlined /> : <MenuFoldOutlined />}
          onClick={onToggleCollapse}
          style={{ width: 56, height: 56, borderRadius: 0, color: colorTextSecondary, fontSize: 15 }}
        />
        <div style={{ display: "flex", alignItems: "center", gap: 10, paddingInlineStart: 4 }}>
          <div
            style={{
              width: 3,
              height: 22,
              background: colorPrimary,
              borderRadius: 2,
              flexShrink: 0
            }}
          />
          <div style={{ lineHeight: 1 }}>
            <Typography.Text
              strong
              style={{ fontSize: 15, display: "block", marginBottom: 3 }}>
              {meta.title}
            </Typography.Text>
            <Typography.Text type="secondary" style={{ fontSize: 11 }}>
              {"Home › " + meta.breadcrumb.join(" › ")}
            </Typography.Text>
          </div>
        </div>
      </div>

      {/* Right */}
      <Space size={2}>
        <Button
          type="text"
          size="small"
          icon={currentTheme === "dark" ? <SunOutlined /> : <MoonOutlined />}
          onClick={toggleTheme}
          style={{ width: 32, height: 32, display: "flex", alignItems: "center", justifyContent: "center" }}
        />
        <Button
          type="text"
          size="small"
          icon={<GlobalOutlined />}
          onClick={() => setLocale(locale === "en" ? "ar" : "en")}
          style={{ width: 32, height: 32, display: "flex", alignItems: "center", justifyContent: "center" }}
        />
        <Popover
          content={notificationContent}
          trigger="click"
          placement="bottomRight"
          overlayStyle={{ width: 340 }}>
          <Badge count={unreadCount} size="small" offset={[-3, 3]}>
            <Button
              type="text"
              size="small"
              icon={<BellOutlined />}
              style={{ width: 32, height: 32, display: "flex", alignItems: "center", justifyContent: "center" }}
            />
          </Badge>
        </Popover>

        <Divider type="vertical" style={{ height: 18, margin: "0 8px" }} />

        <Dropdown menu={{ items: menuItems, onClick: handleMenuClick }} placement="bottomRight">
          <Space style={{ cursor: "pointer" }} size={8}>
            <Avatar size={28} style={{ backgroundColor: colorPrimary, fontSize: 12 }} icon={<UserOutlined />} />
            <div style={{ lineHeight: 1.25 }}>
              <Typography.Text style={{ fontSize: 13, fontWeight: 600, display: "block" }}>
                Admin User
              </Typography.Text>
              <Typography.Text type="secondary" style={{ fontSize: 11, display: "block" }}>
                Administrator
              </Typography.Text>
            </div>
            <CaretDownOutlined style={{ fontSize: 10, color: colorTextSecondary }} />
          </Space>
        </Dropdown>
      </Space>
    </Header>
  )
}
