import { useState, useMemo } from "react"
import {
  UserOutlined,
  VideoCameraOutlined,
  DashboardOutlined,
  SettingOutlined,
  TeamOutlined,
  BarChartOutlined,
  AppstoreOutlined,
  ShoppingCartOutlined,
  SolutionOutlined,
  QuestionCircleOutlined,
  SearchOutlined,
  SafetyCertificateOutlined,
  PieChartOutlined,
  FileTextOutlined,
  ThunderboltOutlined,
  TagsOutlined,
  DatabaseOutlined,
  PartitionOutlined,
  FileDoneOutlined,
  AuditOutlined,
  ContactsOutlined,
  IdcardOutlined,
  CalendarOutlined,
  MoneyCollectOutlined,
  ApartmentOutlined,
  MessageOutlined,
  InfoCircleOutlined,
  PhoneOutlined,
  HistoryOutlined
} from "@ant-design/icons"
import { Layout, Menu, theme, Typography, Input } from "antd"
import type { ItemType } from "antd/es/menu/interface"
import { useTranslation } from "../../lib/providers/i18n-provider"
import { useNavigate, useLocation } from "react-router-dom"

const { Sider } = Layout

interface DashboardSidebarProps {
  collapsed: boolean
}

const routeToKey: Record<string, string> = {
  "/users": "1",
  "/dashboard": "dashboard"
}

const keyToRoute: Record<string, string> = {
  "1": "/users",
  dashboard: "/dashboard"
}

export default function DashboardSidebar({ collapsed }: DashboardSidebarProps) {
  const {
    token: { colorBorder, colorPrimary, colorTextPlaceholder }
  } = theme.useToken()
  const { t } = useTranslation()
  const [searchTerm, setSearchTerm] = useState("")
  const navigate = useNavigate()
  const location = useLocation()

  const selectedKey = routeToKey[location.pathname] || "dashboard"

  const sectionLabel = (text: string) =>
    collapsed ? null : (
      <span
        style={{
          fontSize: 10,
          fontWeight: 700,
          color: "var(--caption-500)",
          letterSpacing: "0.1em",
          textTransform: "uppercase",
          userSelect: "none"
        }}>
        {text}
      </span>
    )

  const sidebarItems: ItemType[] = useMemo(
    () => [
      { key: "dashboard", icon: <DashboardOutlined />, label: t("dashboard") },
      { type: "divider" },
      {
        type: "group",
        label: sectionLabel("Core"),
        children: [
          {
            key: "sub1",
            label: t("userManagement"),
            icon: <TeamOutlined />,
            children: [
              { key: "1", label: t("usersList"), icon: <UserOutlined /> },
              { key: "roles", label: t("rolesPermissions"), icon: <SafetyCertificateOutlined /> }
            ]
          },
          {
            key: "analytics",
            label: t("analytics"),
            icon: <BarChartOutlined />,
            children: [
              { key: "analytics-overview", label: t("overview"), icon: <PieChartOutlined /> },
              { key: "analytics-reports", label: t("reports"), icon: <FileTextOutlined /> },
              { key: "analytics-realtime", label: t("realtime"), icon: <ThunderboltOutlined /> }
            ]
          }
        ]
      },
      { type: "divider" },
      {
        type: "group",
        label: sectionLabel("Business"),
        children: [
          {
            key: "inventory",
            label: t("inventory"),
            icon: <AppstoreOutlined />,
            children: [
              { key: "inventory-products", label: t("products"), icon: <TagsOutlined /> },
              { key: "inventory-stock", label: t("stock"), icon: <DatabaseOutlined /> },
              { key: "inventory-categories", label: t("categories"), icon: <PartitionOutlined /> }
            ]
          },
          {
            key: "sales",
            label: t("sales"),
            icon: <ShoppingCartOutlined />,
            children: [
              { key: "sales-orders", label: t("orders"), icon: <FileDoneOutlined /> },
              { key: "sales-invoices", label: t("invoices"), icon: <AuditOutlined /> },
              { key: "sales-customers", label: t("customers"), icon: <ContactsOutlined /> }
            ]
          },
          {
            key: "hr",
            label: t("hr"),
            icon: <SolutionOutlined />,
            children: [
              { key: "hr-employees", label: t("employees"), icon: <IdcardOutlined /> },
              { key: "hr-attendance", label: t("attendance"), icon: <CalendarOutlined /> },
              { key: "hr-payroll", label: t("payroll"), icon: <MoneyCollectOutlined /> },
              { key: "hr-departments", label: t("departments"), icon: <ApartmentOutlined /> }
            ]
          }
        ]
      },
      { type: "divider" },
      {
        type: "group",
        label: sectionLabel("Administration"),
        children: [
          { key: "monitoring", icon: <VideoCameraOutlined />, label: t("monitoring") },
          {
            key: "support",
            label: t("support"),
            icon: <QuestionCircleOutlined />,
            children: [
              { key: "support-tickets", label: t("tickets"), icon: <MessageOutlined /> },
              { key: "support-faq", label: t("faq"), icon: <InfoCircleOutlined /> },
              { key: "support-contact", label: t("contact"), icon: <PhoneOutlined /> }
            ]
          },
          {
            key: "sub2",
            label: t("system"),
            icon: <SettingOutlined />,
            children: [
              { key: "settings", label: t("settings"), icon: <SettingOutlined /> },
              { key: "logs", label: t("auditLogs"), icon: <HistoryOutlined /> }
            ]
          }
        ]
      }
    ],
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [t, collapsed]
  )

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const filterMenuItems = (items: any[], term: string): any[] => {
    if (!term) return items
    return items.reduce((acc, item) => {
      if (item.type === "divider" || item.type === "group") {
        if (item.children) {
          const filtered = filterMenuItems(item.children, term)
          if (filtered.length > 0) acc.push({ ...item, children: filtered })
        }
        return acc
      }
      const labelStr = typeof item.label === "string" ? item.label : ""
      const matches = labelStr.toLowerCase().includes(term.toLowerCase())
      if (item.children) {
        const filteredChildren = filterMenuItems(item.children, term)
        if (filteredChildren.length > 0) acc.push({ ...item, children: filteredChildren })
        else if (matches) acc.push({ ...item, children: [] })
      } else if (matches) {
        acc.push(item)
      }
      return acc
    }, [])
  }

  const filteredSidebarItems = filterMenuItems(sidebarItems, searchTerm)

  return (
    <Sider
      trigger={null}
      collapsible
      collapsed={collapsed}
      width={240}
      style={{
        height: "100vh",
        position: "sticky",
        top: 0,
        left: 0,
        boxShadow: "2px 0 8px rgba(0,0,0,0.04)",
        overflow: "hidden",
        zIndex: 101
      }}>
      <div style={{ display: "flex", flexDirection: "column", height: "100%" }}>
        {/* Logo */}
        <div
          style={{
            height: 56,
            display: "flex",
            alignItems: "center",
            justifyContent: collapsed ? "center" : "flex-start",
            padding: collapsed ? 0 : "0 16px",
            borderBottom: `1px solid ${colorBorder}`,
            flexShrink: 0,
            transition: "padding 0.2s",
            gap: 10
          }}>
          <div
            style={{
              width: 30,
              height: 30,
              background: colorPrimary,
              borderRadius: 7,
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              color: "white",
              fontWeight: 800,
              fontSize: 15,
              flexShrink: 0,
              letterSpacing: "-0.5px"
            }}>
            E
          </div>
          {!collapsed && (
            <div style={{ overflow: "hidden", lineHeight: 1 }}>
              <Typography.Text
                strong
                style={{ fontSize: 14, display: "block", whiteSpace: "nowrap", marginBottom: 1 }}>
                ERP Pro
              </Typography.Text>
              <Typography.Text
                type="secondary"
                style={{ fontSize: 10, display: "block", whiteSpace: "nowrap" }}>
                Enterprise Edition
              </Typography.Text>
            </div>
          )}
        </div>

        {/* Search */}
        {!collapsed && (
          <div style={{ padding: "8px 12px 4px" }}>
            <Input
              placeholder={t("search")}
              prefix={<SearchOutlined style={{ color: colorTextPlaceholder, fontSize: 12 }} />}
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              allowClear
              variant="filled"
              size="small"
              style={{ borderRadius: 6 }}
            />
          </div>
        )}

        {/* Menu */}
        <div style={{ flex: 1, overflowY: "auto", overflowX: "hidden", paddingBlock: "4px 8px" }}>
          <Menu
            mode="inline"
            inlineCollapsed={collapsed}
            selectedKeys={[selectedKey]}
            style={{ borderRight: 0, fontSize: 13, background: "transparent" }}
            items={filteredSidebarItems}
            onSelect={({ key }) => {
              if (keyToRoute[key]) navigate(keyToRoute[key])
            }}
          />
        </div>

        {/* Bottom footer */}
        {!collapsed && (
          <div
            style={{
              padding: "10px 16px",
              borderTop: `1px solid ${colorBorder}`,
              flexShrink: 0
            }}>
            <Typography.Text type="secondary" style={{ fontSize: 11 }}>
              v1.0.0 &nbsp;&middot;&nbsp; © 2025 ERP Pro
            </Typography.Text>
          </div>
        )}
      </div>
    </Sider>
  )
}
